/// The double-byte tables for a CJK code page (932/936/949/950), or `None` otherwise.
pub(crate) fn double_byte_page(code_page: u16) -> Option<DoubleBytePage> {
    Some(match code_page {
        932 => DoubleBytePage { first: &CP932_FIRST, double: CP932_DOUBLE },
        936 => DoubleBytePage { first: &CP936_FIRST, double: CP936_DOUBLE },
        949 => DoubleBytePage { first: &CP949_FIRST, double: CP949_DOUBLE },
        950 => DoubleBytePage { first: &CP950_FIRST, double: CP950_DOUBLE },
        _ => return None,
    })
}
